单链表
1、单链表的结构
&#x3D;&#x3D;单链表是由一连串的结构（称为结点）组成的，其中每个结点都包含指向下一个结点的指针，单链表最后一个结点的指针为空。&#x3D;&#x3D; 如下：

cstruct node
&#123;
    int date;
    struct node *next;
&#125;

头指针总是指向链表的第一个结点，如果整个链表为空（即不包含任何结点），则将头指针置为NULL。

为了操作方便，往往在首元结点前再增加一个结点，称之为头结点，头结点不存储元素。

头指针指向头结点，头结点的指针域指向首元结点，我们称这种单链表为带头结点的单链表。链表为空时，头结点的指针域为空。




2、单链表的建立（1）定义单链表的数据结构；（2）读取数据；（3）生成新结点；（4）将数据存入结点的成员变量中；（5）将新结点连接到表头或表尾。  重复（2）~（5）直到输入结束。
cvoid CreatList(LinkList head)//尾插法
&#123;
    LinkList p, rear = head;
    int num;

    printf(&quot;输入若干整数，输入-1表示输入结束\n&quot;);
    while (scanf(&quot;%d&quot;,&amp;num),num != -1)
    &#123;
        p = (LinkList)malloc(sizeof(LNode));
        p-&gt;date = num;
        rear-&gt;next = p;
        rear = p;
    &#125;
    rear-&gt;next = NULL;
&#125;
3、单链表的遍历（1）声明一个指针p，并指向首元结点；（2）当p不为空，重复如下两个操作：输出p所指结点中的元素；指针p后移指向下一个元素。
cvoid PrintList(LinkList head)
&#123;
    LinkList p = head-&gt;next;

    while(p)
    &#123;
        printf(&quot;%d &quot;,p-&gt;date);
        p = p-&gt;next;
    &#125;
&#125;
4、单链表的插入（1）在链表中，确定新元素应被加入到哪个结点的后面，该节点就被称为前驱结点，用指针变量pre指向；（2）创建一个新结点，使用一个指针p指向它；（3）将新结点的next指针指向前驱结点next指针指向那个结点；（4）将前驱结点的next指针指向新结点。
cvoid ListInsert(LinkList head,int i,int e)
&#123;
    LinkList p,pre = head;
    int j = 0;

    while (pre &amp;&amp; j&lt;i-1)
    &#123;
        pre = pre-&gt;next;
        j++;
    &#125;

    if(!pre || i&lt;1)
    &#123;
        printf(&quot;i值错误\n&quot;);
        return;
    &#125;

    p = (LinkList)malloc(sizeof(LNode));
    p-&gt;date = e;
    p-&gt;next = pre-&gt;next;
    pre-&gt;next = p;

&#125;
5、单链表的删除（1)定位要删除的结点（用p指向）的前驱结点（用pre指向）；（2）改变前驱结点的next指针，从而使它“绕过”被删除的结点；（3）调用free函数释放删除结点占用的内存空间。
cvoid ListDelete(LinkList head,int i,int *e)
&#123;
    LinkList p,pre = head;
    int j = 0;
    while (pre &amp;&amp; j&lt;i-1)
    &#123;
        pre = pre-&gt;next;
        ++j;
    &#125;
    if(!pre || i&lt;1)
    &#123;
        printf(&quot;i值错误\n&quot;);
        return;
    &#125;

    p = pre-&gt;next;
    pre-&gt;next = p-&gt;next;
    *e = p-&gt;date;
    free(p);
&#125;
6、单链表的综合运用c//单链表的使用
#include&lt;stdio.h&gt;
#include&lt;stdlib.h&gt;

struct node
&#123;
    int date;
    struct node *next;
&#125;;
typedef struct node LNode,*LinkList;

void CreatList(LinkList head);
void PrintList(LinkList head);
void ListDelete(LinkList head,int i,int *e);
void ListInsert(LinkList head,int i,int e);

int main(void)
&#123;
    LinkList head;
    int i,e,select,n;

    head = (LinkList)malloc(sizeof(LNode));
    head-&gt;next  = NULL;

    while (1)
    &#123;
        printf(&quot;1:创建链表\n&quot;);
        printf(&quot;2:在链表中插入元素\n&quot;);
        printf(&quot;3:删除元素\n&quot;);
        printf(&quot;4:输出链表中的元素\n&quot;);
        printf(&quot;0:退出系统\n&quot;);
        scanf(&quot;%d&quot;,&amp;select);

        switch(select)&#123;
            case 1:
                CreatList(head);break;
            case 2:
                printf(&quot;请输入待插入位置和元素:&quot;);
                scanf(&quot;%d%d&quot;,&amp;i,&amp;e);
                ListInsert(head,i,e);break;
            case 3:
                printf(&quot;请输入待删除元素位置:&quot;);
                scanf(&quot;%d&quot;,&amp;i);
                ListDelete(head,i,&amp;e);break;
            case 4:
                PrintList(head);
                printf(&quot;\n&quot;);break;
            case 0:
                exit(0);
        &#125;
    &#125;
    return 0;
&#125;
void CreatList(LinkList head)
&#123;
    LinkList p, rear = head;
    int num;

    printf(&quot;输入若干整数，输入-1表示输入结束\n&quot;);
    while (scanf(&quot;%d&quot;,&amp;num),num != -1)
    &#123;
        p = (LinkList)malloc(sizeof(LNode));
        p-&gt;date = num;
        rear-&gt;next = p;
        rear = p;
    &#125;
    rear-&gt;next = NULL;
&#125;
void PrintList(LinkList head)
&#123;
    LinkList p = head-&gt;next;

    while(p)
    &#123;
        printf(&quot;%d &quot;,p-&gt;date);
        p = p-&gt;next;
    &#125;
&#125;
void ListDelete(LinkList head,int i,int *e)
&#123;
    LinkList p,pre = head;
    int j = 0;
    while (pre &amp;&amp; j&lt;i-1)
    &#123;
        pre = pre-&gt;next;
        ++j;
    &#125;
    if(!pre || i&lt;1)
    &#123;
        printf(&quot;i值错误\n&quot;);
        return;
    &#125;

    p = pre-&gt;next;
    pre-&gt;next = p-&gt;next;
    *e = p-&gt;date;
    free(p);
&#125;
void ListInsert(LinkList head,int i,int e)
&#123;
    LinkList p,pre = head;
    int j = 0;

    while (pre &amp;&amp; j&lt;i-1)
    &#123;
        pre = pre-&gt;next;
        j++;
    &#125;

    if(!pre || i&lt;1)
    &#123;
        printf(&quot;i值错误\n&quot;);
        return;
    &#125;

    p = (LinkList)malloc(sizeof(LNode));
    p-&gt;date = e;
    p-&gt;next = pre-&gt;next;
    pre-&gt;next = p;

&#125;

十进制与八进制的转换
1.格式控制（直接输出）
格式控制包括格式说明和格式字符。

格式说明由“％”和格式字符组成，如％d、％f等。它的作用是将输出的数据转换为指定的格式输出。格式说明总是由“％”字符开始的。不同类型的数据用不同的格式字符。

&#x3D;&#x3D;％d为整型输出；％o以八进制数形式输出整数。&#x3D;&#x3D;


c#include&lt;stdio.h&gt;

int main(void)
&#123;
    int n;
    scanf(&quot;%d&quot;,&amp;n);
    printf(&quot;%o&quot;,n);
    return 0;
&#125;
2.除k取余法（循环）
通过利用循环来实现除k取余法，是比较常见的一种进制转换的方式。

c#include&lt;stdio.h&gt;
#include&lt;math.h&gt;

int main(void)
&#123;
    int n,temp,sum=0,i=0;
    scanf(&quot;%d&quot;,&amp;n);
    while(n)
    &#123;
        temp = n%8;
        n = n/8;
        sum += temp*pow(10,i);
        i++;
    &#125;
    printf(&quot;%d&quot;,sum);
    return 0;
&#125;
3.字符串版
利用字符串的特性来实现进制转换。

c#include&lt;stdio.h&gt;
#include&lt;string.h&gt;
#define N 100

void change (char str[N],int n);
int main(void)
&#123;
    char str[N];
    int n;
    scanf(&quot;%d&quot;,&amp;n);
    change(str,n);
    puts(str);
    return 0; 
&#125;
void change (char str[N],int n)
&#123;
    int i=0;
    while(n)
    &#123;
        str[i]=n%8+&#39;0&#39;;
        i++;
        n/=8;
    &#125;
    str[i]=&#39;\0&#39;;
    strrev(str);
&#125;

4.指针法
结合循环、字符串、指针来实现进制转换。

c#include&lt;stdio.h&gt;
#include&lt;string.h&gt;
#define N 100

void change (char str[N],int n);
int main(void)
&#123;
    char str[N];
    int n;
    scanf(&quot;%d&quot;,&amp;n);
    change(str,n);
    puts(str);
    return 0; 
&#125;
void change (char str[N],int n)
&#123;
    int i=0,d;
    while(n)
    &#123;
        d = n%8;
        str[i]=&quot;0123456789abcdef&quot;[d];
        i++;
        n/=8;
    &#125;
    str[i]=&#39;\0&#39;;
    strrev(str);
&#125;
